function clean(v){return String(v??'').trim()}
function esc(v){return clean(v).replace(/[&<>"']/g,m=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[m]))}
function parseCoordinates(v){const parts=clean(v).replace(/[()]/g,'').split(',').map(Number);return parts.length>=2&&Number.isFinite(parts[0])&&Number.isFinite(parts[1])?[parts[0],parts[1]]:null}
function parseDate(v){const s=clean(v);let m=s.match(/^(\d{4})-(\d{2})-(\d{2})/);if(m)return new Date(+m[1],+m[2]-1,+m[3]);m=s.match(/^(\d{1,2})\/(\d{1,2})\/(\d{4})/);if(m)return new Date(+m[3],+m[2]-1,+m[1]);return null}
function unique(key,source=DATA){return [...new Set(source.map(d=>d[key]).filter(Boolean))].sort((a,b)=>a.localeCompare(b,'es'))}
function fillSelect(el,values,first,keep=false){const old=keep?el.value:'all';el.innerHTML='<option value="all">'+first+'</option>'+values.map(v=>'<option>'+esc(v)+'</option>').join('');el.value=[...el.options].some(o=>o.value===old)?old:'all'}
function currentOrg(){return view==='foundations'?'foundation':'education'}
function baseOrg(){return view==='more'?DATA:DATA.filter(d=>d.org===currentOrg())}
function syncOptions(changed){const base=baseOrg();if(changed!=='city')fillSelect(filters.city,unique('city',base),'Todas',true);const cityRows=base.filter(d=>filters.city.value==='all'||d.city===filters.city.value);if(changed!=='zone')fillSelect(filters.zone,unique('zone',cityRows),'Todas',true);const serviceValues=[...new Set(base.map(d=>Number(d.services)).filter(n=>Number.isFinite(n)&&n>0))].sort((a,b)=>a-b).map(String);fillSelect(filters.services,serviceValues,'Todos',true)}
function inSize(n,v){return v==='all'||(v==='0-200'&&n<=200)||(v==='201-500'&&n>200&&n<=500)||(v==='501-1000'&&n>500&&n<=1000)||(v==='1001+'&&n>1000)}
function filtered(includeSearch=false){const q=includeSearch?$('#searchInput').value.toLowerCase():'';return DATA.filter(d=>(view==='more'||d.org===currentOrg())&&(filters.city.value==='all'||d.city===filters.city.value)&&(filters.zone.value==='all'||d.zone===filters.zone.value)&&(filters.site.value==='all'||d.type===filters.site.value)&&(filters.internet.value==='all'||d.internet===filters.internet.value)&&(filters.services.value==='all'||String(Number(d.services))===filters.services.value)&&inSize(d.people,filters.size.value)&&(!q||(d.client+' '+d.institution+' '+d.site).toLowerCase().includes(q)))}
function metric(rows){return view==='people'?rows.reduce((a,d)=>a+d.people,0):rows.length}
function renderKpis(){
 const rs=filtered(),foundation=currentOrg()==='foundation',uniqueInstitutions=new Set(rs.map(d=>d.institution.toLowerCase())).size,people=rs.reduce((a,d)=>a+d.people,0),cities=new Set(rs.map(d=>d.city).filter(Boolean)).size;
 const siteScope=filters.site.value==='Principal'?'Principales':filters.site.value==='Sede'?'Sedes':'Principales + sedes';
 $('#kpis').innerHTML='<article class="kpi primary"><span>'+(foundation?'Centros de fundaciones conectados':'Instituciones educativas conectadas')+'</span><strong>'+fmt(rs.length)+'</strong><small>'+siteScope+'</small></article><article class="kpi"><span>'+(foundation?'Fundaciones':'Instituciones educativas')+'</span><strong>'+fmt(uniqueInstitutions)+'</strong>'+(foundation?'<small>Organizaciones beneficiadas</small>':'')+'</article><article class="kpi"><span>'+(foundation?'Beneficiarios registrados':'Alumnos conectados')+'</span><strong>'+fmt(people)+'</strong></article><article class="kpi accent"><span>Ciudades con presencia</span><strong>'+cities+'</strong><small>'+(foundation?'Fundaciones':'Instituciones educativas')+'</small></article>'
}
function addMonth(d,n=1){return new Date(d.getFullYear(),d.getMonth()+n,1)}
function periodGroups(rs){
 const orgDates=baseOrg().map(d=>parseDate(d.date)).filter(Boolean).sort((a,b)=>a-b);if(!orgDates.length)return[];
 const first=orgDates[0],today=new Date(),last=orgDates[orgDates.length-1]>today?orgDates[orgDates.length-1]:today,items=[];
 if(period==='year'){for(let y=first.getFullYear();y<=last.getFullYear();y++)items.push({key:String(y),label:String(y)})}
 else{for(let d=new Date(first.getFullYear(),first.getMonth(),1);d<=new Date(last.getFullYear(),last.getMonth(),1);d=addMonth(d))items.push({key:d.getFullYear()+'-'+String(d.getMonth()+1).padStart(2,'0'),label:new Intl.DateTimeFormat('es-CO',{month:'short',year:'2-digit'}).format(d)})}
 let cumulative=0;return items.map(item=>{const list=rs.filter(r=>{const d=parseDate(r.date);if(!d)return false;const key=period==='year'?String(d.getFullYear()):d.getFullYear()+'-'+String(d.getMonth()+1).padStart(2,'0');return key===item.key});cumulative+=metric(list);return{...item,value:cumulative}})
}
function renderGrowth(){
 const rs=filtered(),all=periodGroups(rs);
 const arr=period==='month'?all.filter((x,i)=>x.value!==(i?all[i-1].value:0)):all;
 $('#growthTitle').textContent='Crecimiento de '+(view==='foundations'?'fundaciones':view==='schools'?'sedes':'alumnos');
 const chart=$('#growthChart');chart.classList.toggle('monthly',period==='month');chart.classList.toggle('line-mode',chartType==='line');
 if(!arr.length){chart.innerHTML='<p class="empty">No hay cambios para estos filtros.</p>';return}
 const width=Math.max(760,arr.length*(period==='month'?118:150)),height=340,pad={left:62,right:24,top:28,bottom:62},plotW=width-pad.left-pad.right,plotH=height-pad.top-pad.bottom,max=Math.max(1,...arr.map(x=>x.value));
 const x=i=>pad.left+(arr.length===1?plotW/2:i*plotW/(arr.length-1)),y=v=>pad.top+plotH-v/max*plotH;
 const ticks=[0,.25,.5,.75,1],grid=ticks.map(t=>{const val=Math.round(max*t),py=y(val);return '<line class="growth-gridline" x1="'+pad.left+'" y1="'+py+'" x2="'+(width-pad.right)+'" y2="'+py+'"></line><text class="growth-y-label" x="'+(pad.left-10)+'" y="'+(py+4)+'" text-anchor="end">'+fmt(val)+'</text>'}).join('');
 const labels=arr.map((d,i)=>'<text class="growth-x-label" transform="translate('+x(i)+','+(height-34)+') rotate('+(period==='month'?-32:0)+')" text-anchor="'+(period==='month'?'end':'middle')+'">'+esc(d.label)+'</text>').join('');
 let marks='';
 if(chartType==='bar'){const barW=Math.min(46,Math.max(24,plotW/Math.max(1,arr.length)*.55));marks=arr.map((d,i)=>{const py=y(d.value),h=pad.top+plotH-py;return '<rect class="growth-svg-bar" x="'+(x(i)-barW/2)+'" y="'+py+'" width="'+barW+'" height="'+Math.max(2,h)+'" rx="7"></rect><text class="growth-value" x="'+x(i)+'" y="'+Math.max(16,py-8)+'" text-anchor="middle">'+fmt(d.value)+'</text>'}).join('')}
 else{const pts=arr.map((d,i)=>x(i)+','+y(d.value)).join(' ');marks='<polyline class="growth-line" points="'+pts+'"></polyline>'+arr.map((d,i)=>'<circle class="growth-point" cx="'+x(i)+'" cy="'+y(d.value)+'" r="5"></circle><text class="growth-value" x="'+x(i)+'" y="'+Math.max(16,y(d.value)-10)+'" text-anchor="middle">'+fmt(d.value)+'</text>').join('')}
 chart.innerHTML='<div class="growth-svg-inner" style="width:'+width+'px"><svg viewBox="0 0 '+width+' '+height+'" role="img" aria-label="'+esc($('#growthTitle').textContent)+'">'+grid+'<line class="growth-axis" x1="'+pad.left+'" y1="'+pad.top+'" x2="'+pad.left+'" y2="'+(pad.top+plotH)+'"></line><line class="growth-axis" x1="'+pad.left+'" y1="'+(pad.top+plotH)+'" x2="'+(width-pad.right)+'" y2="'+(pad.top+plotH)+'"></line>'+marks+labels+'</svg></div>';
 if(period==='month')requestAnimationFrame(()=>{chart.scrollLeft=chart.scrollWidth});
}
function renderCities(){const rs=filtered(),map=new Map();rs.forEach(d=>{if(!map.has(d.city))map.set(d.city,[]);map.get(d.city).push(d)});const arr=[...map].map(([city,list])=>[city,metric(list)]).sort((a,b)=>b[1]-a[1]),max=Math.max(1,...arr.map(x=>x[1]));$('#cityChart').innerHTML=arr.length?arr.map(x=>'<div class="bar-row"><span>'+esc(x[0])+'</span><div class="track"><i style="width:'+x[1]/max*100+'%"></i></div><b>'+fmt(x[1])+'</b></div>').join(''):'<p class="empty">Sin resultados.</p>'}
function group(rs,key){return Object.entries(rs.reduce((a,d)=>{const k=clean(d[key])||'Sin información';a[k]=(a[k]||0)+1;return a},{})).sort((a,b)=>b[1]-a[1])}
function renderConnectivity(){const rs=filtered(),yes=rs.filter(d=>d.internet==='SI'||d.internet==='Sí').length,no=rs.length-yes,pct=Math.round(yes/Math.max(1,rs.length)*100);$('#internetSummary').innerHTML='<div class="donut" style="background:conic-gradient(var(--green) 0 '+pct+'%,var(--yellow) '+pct+'% 100%)"></div><div class="donut-labels"><div><i class="dot" style="background:var(--green)"></i>Tenían internet · '+yes+'</div><div><i class="dot" style="background:var(--yellow)"></i>No tenían · '+no+'</div></div>';const providers=group(rs,'provider').slice(0,7),pm=Math.max(1,...providers.map(x=>x[1]));$('#providerChart').innerHTML=providers.map(x=>'<div class="provider-item"><span>'+esc(x[0])+'</span><div class="track"><i style="width:'+x[1]/pm*100+'%"></i></div><b>'+x[1]+'</b></div>').join('')||'<p class="empty">Sin datos.</p>';$('#qualityChart').innerHTML=group(rs,'quality').map(x=>'<div class="quality"><b>'+x[1]+'</b><small>'+esc(x[0])+'</small><em>'+((x[1]/Math.max(1,rs.length))*100).toLocaleString('es-CO',{maximumFractionDigits:1})+'%</em></div>').join('')||'<p class="empty">Sin datos.</p>'}
function cell(d,key){
 const value=d[key];if(key==='coordinates'){const point=parseCoordinates(value);return point?'<a class="map-link" href="https://www.google.com/maps?q='+point[0]+','+point[1]+'" target="_blank" rel="noopener">Ver mapa</a>':'<span class="cell-text">Sin información</span>'}if(key==='client')return '<a class="client-link" href="https://sysbrazo.fibrazo.com.co/clients?brochure_id=&document_id=&full_name=&phone_number=&gaiia_id='+encodeURIComponent(value)+'&gaiia_status=&email=&has_credit=0&validated_in_dian=0&payment_filter=0&churn_risk=&recharge_block_filter=0&coordinates=&city_id=0&neighborhood_id=&internet_plan_id=&tv_plan_id=&troncal_limit_id=&tv_status_id=&tv_addon_status_id=&tv_addon_tv_plan_id=&tv_pending=&stratum=&refered_code_installer=&client_type_id=&with_incident=0&is_reactivated=0" target="_blank" rel="noopener">'+esc(value)+'</a>';
 if(key==='people')return value?fmt(value):'No aplica';
 if(key.toLowerCase().includes('email')&&value)return '<a class="data-link cell-text" title="'+esc(value)+'" href="mailto:'+encodeURIComponent(value)+'">'+esc(value)+'</a>';
 if(key.toLowerCase().includes('phone')&&value)return '<a class="data-link" href="tel:'+value.replace(/\D/g,'')+'">'+esc(value)+'</a>';
 if(key==='type')return '<span class="pill">'+esc(value||'Sin información')+'</span>';
 if(key==='internet')return '<span class="bool '+((value==='NO'||value==='No')?'no':'')+'">'+esc(value||'Sin información')+'</span>';
 return '<span class="cell-text" title="'+esc(value||'Sin información')+'">'+esc(value||'Sin información')+'</span>'
}
function sizeBucket(d){const n=d.people;if(n<=200)return '0–200';if(n<=500)return '201–500';if(n<=1000)return '501–1.000';if(n<=1500)return '1.001–1.500';if(n<=2000)return '1.501–2.000';return 'Más de 2.000'}
function renderSizes(){const panel=$('.school-size');if(currentOrg()==='foundation'){panel.style.display='none';return}panel.style.display='block';const rs=filtered(),order=['0–200','201–500','501–1.000','1.001–1.500','1.501–2.000','Más de 2.000'],counts=Object.fromEntries(order.map(x=>[x,0]));rs.forEach(d=>counts[sizeBucket(d)]++);const max=Math.max(1,...Object.values(counts));$('#sizeChart').innerHTML=order.map(k=>'<div class="size-row"><span>'+k+'</span><div class="track"><i style="width:'+counts[k]/max*100+'%"></i></div><b>'+counts[k]+'</b></div>').join('');const total=rs.length,avg=total?Math.round(rs.reduce((a,d)=>a+d.people,0)/total):0,largest=rs.slice().sort((a,b)=>b.people-a.people)[0];$('#sizeSummary').innerHTML='<article><span>Promedio por sede</span><b>'+fmt(avg)+'</b></article><article><span>Sedes analizadas</span><b>'+fmt(total)+'</b></article><article><span>Institución con más alumnos</span><b>'+(largest?fmt(largest.people)+' alumnos':'0 alumnos')+'</b><small>'+(largest?esc(largest.institution):'Sin resultados')+'</small></article>'}
function activeColumns(){
 const all=DETAIL[detailTab];
 if(!visibleColumns[detailTab])visibleColumns[detailTab]=new Set(all.map(c=>c[0]));
 visibleColumns[detailTab].add('client');
 return all.filter(c=>visibleColumns[detailTab].has(c[0]));
}
function sortValue(d,key){
 const v=d[key];
 if(['people','days','services','computers','tablets'].includes(key))return Number(String(v??0).replace(/\D/g,''))||0;
 if(key==='date')return parseDate(v)?.getTime()||0;
 return clean(v).toLocaleLowerCase('es');
}
function renderColumnsMenu(){
 const selected=visibleColumns[detailTab]||new Set(DETAIL[detailTab].map(c=>c[0]));
 $('#columnsMenu').innerHTML=DETAIL[detailTab].map(([key,label])=>'<label><input type="checkbox" data-column="'+key+'" '+(selected.has(key)?'checked':'')+' '+(key==='client'?'disabled title="Columna fija"':'')+'><span>'+label.replace(/:/g,'')+'</span></label>').join('');
}
function renderLocationsMap(rs){
 const panel=$('#locationsMapPanel');panel.hidden=detailTab!=='map';if(detailTab!=='map')return;
 $('#recordCount').textContent=fmt(rs.length)+' registros';
 $('#mapCount').innerHTML='<a class="my-maps-title-link" href="https://www.google.com/maps/d/u/0/edit?mid=1IP8S422GKdDmvrAtU0ZPTR7ql9P3CUs&ll=9.984108371108164%2C-75.01877050081453&z=8" target="_blank" rel="noopener">Dash-impacto-social-fibrazo ↗</a>';
 $('#locationsMap').innerHTML='<iframe class="my-maps-frame" title="Mapa de instituciones educativas y fundaciones" src="https://www.google.com/maps/d/embed?mid=1IP8S422GKdDmvrAtU0ZPTR7ql9P3CUs&ehbc=2E312F" loading="lazy" allowfullscreen></iframe>';
}
function renderMainMoreInfo(){
 const isMore=view==='more',panel=$('#moreInfoView');
 panel.hidden=!isMore;
 const dashboardSections=['#kpis','.charts','.connectivity','.school-size','.records'];
 dashboardSections.forEach(selector=>{const el=$(selector);if(el)el.hidden=isMore});
 if(!isMore)return false;
 const rs=filtered();
 const uniqueOrgs=new Set(rs.map(d=>(d.org+'|'+clean(d.institution)).toLowerCase())).size;
 const education=rs.filter(d=>d.org==='education').length,foundations=rs.filter(d=>d.org==='foundation').length;
 const multi=rs.filter(d=>Number(d.services)>1).length;
 const principals=rs.filter(d=>d.type==='Principal').length;
 const sites=rs.filter(d=>d.type==='Sede').length;
 const extra=rs.reduce((sum,d)=>sum+Math.max(0,(Number(d.services)||0)-1),0);
 const people=rs.reduce((sum,d)=>sum+(Number(d.people)||0),0);
 const cities=new Set(rs.map(d=>d.city).filter(Boolean)).size;
 const group=(key,rows=rs)=>Object.entries(rows.reduce((acc,d)=>{const value=clean(d[key])||'Sin información';acc[value]=(acc[value]||0)+1;return acc},{})).sort((a,b)=>b[1]-a[1]);
 const bars=(items)=>items.map(([label,count])=>'<div class="more-bar"><span>'+esc(label)+'</span><i><b style="width:'+Math.max(4,Math.round(count/Math.max(1,items[0]?.[1]||1)*100))+'%"></b></i><strong>'+fmt(count)+'</strong></div>').join('');
 const services=group('services').map(([label,count])=>[(label==='Sin información'?label:label+' servicio'+(label==='1'?'':'s')),count]);
 const orgTypes=[['Instituciones educativas',education],['Fundaciones',foundations]];
 const educationPct=rs.length?education/rs.length*100:0;
 const pieBackground=rs.length?'conic-gradient(var(--green) 0 '+educationPct+'%, var(--yellow) '+educationPct+'% 100%)':'#13231d';
 $('#moreInfoContent').innerHTML='<div class="more-hero-kpis"><article class="featured"><span>Ubicaciones conectadas</span><strong>'+fmt(rs.length)+'</strong><small>'+fmt(uniqueOrgs)+' organizaciones beneficiadas</small></article><article><span>Alumnos y beneficiarios</span><strong>'+fmt(people)+'</strong><small>Impacto social acumulado</small></article><article><span>Ciudades con presencia</span><strong>'+fmt(cities)+'</strong><small>Cobertura territorial</small></article></div><div class="more-kpis"><article><span>Sedes con más de un servicio</span><strong>'+fmt(multi)+'</strong><small>Instalaciones múltiples</small></article><article><span>Servicios adicionales</span><strong>'+fmt(extra)+'</strong><small>Por encima del primer servicio</small></article><article><span>Principales instaladas</span><strong>'+fmt(principals)+'</strong><small>Sedes principales</small></article><article><span>Sedes instaladas</span><strong>'+fmt(sites)+'</strong><small>Sedes y centros asociados</small></article></div><div class="more-grids wide"><section><span class="eyebrow">TIPO DE ORGANIZACIÓN</span><h3>Gráfico de torta</h3><div class="more-pie-layout"><div class="more-pie" style="background:'+pieBackground+'"><div><strong>'+fmt(rs.length)+'</strong><span>Total</span></div></div><div class="more-pie-legend"><p><i class="education"></i><span>Instituciones educativas</span><strong>'+fmt(education)+'</strong></p><p><i class="foundation"></i><span>Fundaciones</span><strong>'+fmt(foundations)+'</strong></p></div></div></section><section><span class="eyebrow">SERVICIOS INSTALADOS</span><h3>Distribución por cantidad</h3>'+bars(services)+'</section><section class="administration-wide"><span class="eyebrow">TIPO DE ADMINISTRACIÓN</span><h3>Distribución de organizaciones</h3>'+bars(group('administration'))+'</section></div>';
 return true;
}
function renderTable(){
 const foundation=currentOrg()==='foundation';
 let rs=filtered(true).slice();
 const special=detailTab==='map';
 $('.table-tools').hidden=special;$('#tableWrap').hidden=special;
 renderLocationsMap(rs);
 if(detailTab==='map'){$('#tableTitle').textContent=foundation?'Mapa de fundaciones':'Mapa de instituciones educativas';return}
 const columns=activeColumns();
 if(sortKey&&DETAIL[detailTab].some(c=>c[0]===sortKey))rs.sort((a,b)=>{const x=sortValue(a,sortKey),y=sortValue(b,sortKey);const result=typeof x==='number'?x-y:String(x).localeCompare(String(y),'es',{numeric:true});return sortDirection==='asc'?result:-result});
 $('#tableTitle').textContent=foundation?'Fundaciones conectadas':'Instituciones educativas conectadas';
 $('#recordCount').textContent=fmt(rs.length)+' registros';
 $('#recordsHead').innerHTML='<tr>'+columns.map(([key,label])=>'<th><button class="sort-button '+(sortKey===key?'sorted':'')+'" data-sort="'+key+'" type="button">'+label.replace(/:/g,'')+'<i>'+(sortKey===key?(sortDirection==='asc'?' ↑':' ↓'):'')+'</i></button></th>').join('')+'</tr>';
 $('#recordsBody').innerHTML=rs.length?rs.map(d=>'<tr>'+columns.map(c=>'<td class="'+(c[0]==='institution'?'institution-cell':c[0]==='site'?'site-cell':'')+'">'+cell(d,c[0])+'</td>').join('')+'</tr>').join(''):'<tr><td colspan="'+Math.max(1,columns.length)+'" class="empty">No hay resultados para estos filtros.</td></tr>';
 renderColumnsMenu();
}
function render(){if(renderMainMoreInfo())return;renderKpis();renderGrowth();renderCities();renderConnectivity();renderSizes();renderTable()}
Object.entries(filters).forEach(([name,el])=>el.addEventListener('change',()=>{if(name==='city')syncOptions('city');render()}));
$('#searchInput').addEventListener('input',renderTable);
$('#clearFilters').addEventListener('click',()=>{filters.site.value='all';filters.size.value='all';filters.internet.value='all';filters.services.value='all';$('#searchInput').value='';fillSelect(filters.city,unique('city',baseOrg()),'Todas');filters.city.value='all';fillSelect(filters.zone,unique('zone',baseOrg()),'Todas');filters.zone.value='all';period='year';[...document.querySelectorAll('.period-switch button')].forEach((b,i)=>b.classList.toggle('active',i===0));[...document.querySelectorAll('.chart-switch button')].forEach((b,i)=>b.classList.toggle('active',i===0));chartType='bar';render()});
$$('.view-switch button').forEach(b=>b.addEventListener('click',()=>{$$('.view-switch button').forEach(x=>x.classList.remove('active'));b.classList.add('active');view=b.dataset.view;filters.city.value='all';filters.zone.value='all';syncOptions();render()}));
[...document.querySelectorAll('.period-switch button')].forEach(b=>b.addEventListener('click',()=>{[...document.querySelectorAll('.period-switch button')].forEach(x=>x.classList.remove('active'));b.classList.add('active');period=b.dataset.period;renderGrowth()}));
[...document.querySelectorAll('.chart-switch button')].forEach(b=>b.addEventListener('click',()=>{[...document.querySelectorAll('.chart-switch button')].forEach(x=>x.classList.remove('active'));b.classList.add('active');chartType=b.dataset.chart;renderGrowth()}));
[...document.querySelectorAll('.detail-tabs button')].forEach(b=>b.addEventListener('click',()=>{[...document.querySelectorAll('.detail-tabs button')].forEach(x=>x.classList.remove('active'));b.classList.add('active');detailTab=b.dataset.detail;sortKey='';sortDirection='asc';$('#columnsMenu').hidden=true;$('#columnsButton').setAttribute('aria-expanded','false');renderTable()}));
$('#recordsHead').addEventListener('click',e=>{const button=e.target.closest('[data-sort]');if(!button)return;const key=button.dataset.sort;if(sortKey===key)sortDirection=sortDirection==='asc'?'desc':'asc';else{sortKey=key;sortDirection='asc'}renderTable()});
$('#columnsButton').addEventListener('click',()=>{const menu=$('#columnsMenu');menu.hidden=!menu.hidden;$('#columnsButton').setAttribute('aria-expanded',String(!menu.hidden))});
$('#columnsMenu').addEventListener('change',e=>{const input=e.target.closest('[data-column]');if(!input)return;if(input.dataset.column==='client'){input.checked=true;return}const selected=visibleColumns[detailTab]||(visibleColumns[detailTab]=new Set(DETAIL[detailTab].map(c=>c[0])));if(input.checked)selected.add(input.dataset.column);else if(selected.size>1)selected.delete(input.dataset.column);else input.checked=true;renderTable()});
document.addEventListener('click',e=>{if(!e.target.closest('.column-picker')){$('#columnsMenu').hidden=true;$('#columnsButton').setAttribute('aria-expanded','false')}});
